import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import AdminLayout from '../components/admin/AdminLayout';
import authService from '../services/authService';
import api from '../services/api';

export default function AdminDashboard() {
  const navigate = useNavigate();
  const [cmsStatus, setCmsStatus] = useState('loading');
  const [userPages, setUserPages] = useState([]);
  const [showNewPageModal, setShowNewPageModal] = useState(false);
  const [newPageForm, setNewPageForm] = useState({ slug: '', title: '' });
  const [contentData, setContentData] = useState({
    hero: null,
    benefits: null,
    features: null,
    pricing: null,
    steps: null,
    faq: null,
    cta: null
  });
  const [editingSection, setEditingSection] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [formData, setFormData] = useState({});

  useEffect(() => {
    if (!authService.isAdmin()) {
      navigate('/login');
      return;
    }
    checkCmsStatus();
  }, []);

  const checkCmsStatus = async () => {
    try {
      const response = await api.get('/admin/test');
      setCmsStatus('available');
      loadUserPages();
    } catch (e) {
      setCmsStatus('unavailable');
    }
  };

  const loadUserPages = async () => {
    try {
      const response = await api.get('/admin/pages');
      setUserPages(response.data || []);
    } catch (e) {
      setUserPages([]);
    }
  };

  const handleCreatePage = async (e) => {
    e.preventDefault();
    try {
      await api.post('/admin/pages', newPageForm);
      setShowNewPageModal(false);
      setNewPageForm({ slug: '', title: '' });
      loadUserPages();
    } catch (err) {
      alert('Erreur lors de la création de la page');
    }
  };

  const handleDeletePage = async (pageId) => {
    if (!window.confirm('Supprimer cette page ?')) return;
    try {
      await api.delete(`/admin/pages/${pageId}`);
      loadUserPages();
    } catch (err) {
      alert('Erreur lors de la suppression');
    }
  };

  const loadContentData = () => {
    setContentData({
      hero: {
        title: "Devis Gratuit",
        subtitle: "Assurance Décennale Électricien",
        buttonText: "Obtenir mon devis",
        description: "Comparez les meilleures offres d'assurance décennale pour electricien"
      },
      benefits: {
        title: "Pourquoi nous choisir ?",
        items: [
          { title: "Devis gratuit", description: "Obtenez votre devis en 2 minutes" },
          { title: "Comparatif impartial", description: "Nous comparons toutes les assurances" },
          { title: "Réponse sous 24h", description: "Notre équipe vous répond rapidement" }
        ]
      },
      features: {
        title: "Nos garanties",
        items: [
          { title: "Responsabilité Civile Professionnelle", description: "Obligatoire selon la loi Spinetta" },
          { title: "Garantie Décennale", description: "Couverture pendant 10 ans" },
          { title: "Assistance juridique", description: "Aide en cas de litige" }
        ]
      },
      pricing: {
        title: "Tarifs transparents",
        plans: [
          { name: "Solo", price: "À partir de 35€/mois", features: ["RC Pro", "Décennale", "Sans franchise"] },
          { name: "Artisan", price: "À partir de 65€/mois", features: ["RC Pro", "Décennale", "Franchise réduite", "Assistance"] },
          { name: "Entreprise", price: "Sur devis", features: ["RC Pro", "Décennale", "Multirisque", "Support dédié"] }
        ]
      },
      steps: {
        title: "Comment ça marche ?",
        steps: [
          { title: "1. Comparez", description: "Laissez votre demande de devis" },
          { title: "2. Recevez", description: "Obtenez plusieurs offres en 24h" },
          { title: "3. Économisez", description: "Choisissez la meilleure offre" }
        ]
      },
      faq: {
        title: "Questions fréquentes",
        questions: [
          { question: "L'assurance décennale est-elle obligatoire ?", answer: "Oui, selon la loi Spinetta, tout professionnel du bâtiment doit être assurée." },
          { question: "Combien de temps dure la couverture ?", answer: "La garantie décennale couvre pendant 10 ans après la fin des travaux." },
          { question: "Quel est le délai de réponse ?", answer: "Nous vous répondons sous 24h maximum." }
        ]
      },
      cta: {
        title: "Prêt à economiser ?",
        buttonText: "Obtenir mon devis gratuit",
        description: "Devis personnalisé et gratuit"
      }
    });
  };

  useEffect(() => {
    loadContentData();
  }, []);

  const handleEditSection = (sectionName, data) => {
    setEditingSection({ name: sectionName, data });
    setFormData(data);
    setShowModal(true);
  };

  const handleSaveSection = (e) => {
    e.preventDefault();
    setContentData({
      ...contentData,
      [editingSection.name]: formData
    });
    setShowModal(false);
    alert('Contenu mis à jour avec succès !');
  };

  const getSectionIcon = (name) => {
    const icons = {
      hero: 'fa-bolt',
      benefits: 'fa-handshake',
      features: 'fa-star',
      pricing: 'fa-tag',
      steps: 'fa-list-ol',
      faq: 'fa-question-circle',
      cta: 'fa-bullhorn'
    };
    return icons[name] || 'fa-th-large';
  };

  const getSectionTitle = (name) => {
    const titles = {
      hero: 'Hero (En-tête)',
      benefits: 'Avantages',
      features: 'Caractéristiques',
      pricing: 'Tarifs',
      steps: 'Étapes',
      faq: 'FAQ',
      cta: 'Call to Action'
    };
    return titles[name] || name;
  };

  return (
    <AdminLayout>
      <div>
        {/* Page Header */}
        <div className="mb-6 flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Gestion du Site Web</h1>
            <p className="text-gray-600 mt-1 text-lg">
              Modifiez le contenu de votre site directement
            </p>
          </div>
          <button
            onClick={() => setShowNewPageModal(true)}
            className="bg-yellow-500 text-white px-5 py-2.5 rounded-lg hover:bg-yellow-600 font-medium flex items-center gap-2 shadow-md"
          >
            <i className="fas fa-plus"></i>
            Nouvelle Page
          </button>
        </div>

        {/* User Created Pages */}
        {userPages.length > 0 && (
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden mb-6">
            <div className="p-5 border-b border-gray-100 bg-purple-50">
              <h2 className="text-xl font-bold text-gray-900 flex items-center gap-2">
                <i className="fas fa-file-alt text-purple-600"></i>
                Pages Créées
              </h2>
            </div>
            <div className="divide-y divide-gray-100">
              {userPages.map((page) => (
                <div key={page.id} className="p-4 flex items-center justify-between hover:bg-gray-50">
                  <div>
                    <h3 className="font-medium text-gray-900">{page.title}</h3>
                    <p className="text-sm text-gray-500">/{page.slug}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className={`px-2 py-1 text-xs rounded-full ${page.isPublished ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-600'}`}>
                      {page.isPublished ? 'Publié' : 'Brouillon'}
                    </span>
                    <button className="text-blue-600 hover:text-blue-800 p-2">
                      <i className="fas fa-edit"></i>
                    </button>
                    <button onClick={() => handleDeletePage(page.id)} className="text-red-600 hover:text-red-800 p-2">
                      <i className="fas fa-trash"></i>
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Content Sections List */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-5 border-b border-gray-100 bg-yellow-50">
            <h2 className="text-xl font-bold text-gray-900 flex items-center gap-2">
              <i className="fas fa-layer-group text-yellow-600"></i>
              Sections du Site
            </h2>
            <p className="text-sm text-gray-500 mt-1">
              Cliquez sur "Modifier" pour changer le contenu de chaque section
            </p>
          </div>

          <div className="divide-y divide-gray-100">
            {Object.keys(contentData).map((sectionName) => (
              <div
                key={sectionName}
                className="p-4 hover:bg-gray-50 cursor-pointer transition-colors border-b border-gray-100 last:border-b-0"
                onClick={() => handleEditSection(sectionName, contentData[sectionName])}
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-yellow-100 rounded-lg flex items-center justify-center flex-shrink-0">
                      <i className={`fas ${getSectionIcon(sectionName)} text-yellow-600 text-lg`}></i>
                    </div>
                    <div>
                      <h3 className="font-medium text-gray-900">{getSectionTitle(sectionName)}</h3>
                      <p className="text-sm text-gray-500">
                        {contentData[sectionName]?.title || 'Section configurée'}
                      </p>
                    </div>
                  </div>
                  <button className="bg-yellow-500 text-white px-4 py-2 rounded-lg hover:bg-yellow-600 text-sm font-medium flex items-center gap-2">
                    <i className="fas fa-edit"></i>
                    Modifier
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Edit Modal */}
        {showModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-lg max-h-[80vh] overflow-y-auto">
              <div className="p-5 border-b border-gray-100 flex items-center justify-between">
                <h2 className="text-xl font-bold text-gray-900">
                  {getSectionTitle(editingSection.name)}
                </h2>
                <button 
                  onClick={() => setShowModal(false)}
                  className="text-gray-400 hover:text-gray-600 text-2xl"
                >
                  ×
                </button>
              </div>
              <form onSubmit={handleSaveSection} className="p-5 space-y-4">
                {editingSection.name === 'hero' && (
                  <>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Titre principal</label>
                      <input
                        type="text"
                        value={formData.title || ''}
                        onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Sous-titre</label>
                      <input
                        type="text"
                        value={formData.subtitle || ''}
                        onChange={(e) => setFormData({ ...formData, subtitle: e.target.value })}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Texte du bouton</label>
                      <input
                        type="text"
                        value={formData.buttonText || ''}
                        onChange={(e) => setFormData({ ...formData, buttonText: e.target.value })}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                      />
                    </div>
                  </>
                )}

                {(editingSection.name === 'benefits' || editingSection.name === 'features') && (
                  <>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Titre de la section</label>
                      <input
                        type="text"
                        value={formData.title || ''}
                        onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Éléments (JSON)</label>
                      <textarea
                        value={JSON.stringify(formData.items || [], null, 2)}
                        onChange={(e) => {
                          try {
                            setFormData({ ...formData, items: JSON.parse(e.target.value) });
                          } catch {}
                        }}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none font-mono text-sm"
                        rows={8}
                      />
                    </div>
                  </>
                )}

                {editingSection.name === 'cta' && (
                  <>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Titre</label>
                      <input
                        type="text"
                        value={formData.title || ''}
                        onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                      <input
                        type="text"
                        value={formData.description || ''}
                        onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Texte du bouton</label>
                      <input
                        type="text"
                        value={formData.buttonText || ''}
                        onChange={(e) => setFormData({ ...formData, buttonText: e.target.value })}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                      />
                    </div>
                  </>
                )}

                <div className="flex gap-2 pt-4">
                  <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50">
                    Annuler
                  </button>
                  <button type="submit" className="flex-1 px-4 py-2 bg-yellow-500 text-white rounded-lg hover:bg-yellow-600">
                    Sauvegarder
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {/* New Page Modal */}
        {showNewPageModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-md">
              <div className="p-5 border-b border-gray-100 flex items-center justify-between">
                <h2 className="text-xl font-bold text-gray-900">
                  Créer une nouvelle page
                </h2>
                <button 
                  onClick={() => setShowNewPageModal(false)}
                  className="text-gray-400 hover:text-gray-600 text-2xl"
                >
                  ×
                </button>
              </div>
              <form onSubmit={handleCreatePage} className="p-5 space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Titre de la page *</label>
                  <input
                    type="text"
                    value={newPageForm.title}
                    onChange={(e) => setNewPageForm({ ...newPageForm, title: e.target.value, slug: e.target.value.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '') })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                    placeholder="Ma nouvelle page"
                    required
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">URL (slug) *</label>
                  <input
                    type="text"
                    value={newPageForm.slug}
                    onChange={(e) => setNewPageForm({ ...newPageForm, slug: e.target.value.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '') })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                    placeholder="ma-nouvelle-page"
                    required
                  />
                  <p className="text-xs text-gray-500 mt-1">URL: /{newPageForm.slug || '...'}</p>
                </div>
                <div className="flex gap-2 pt-4">
                  <button type="button" onClick={() => setShowNewPageModal(false)} className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50">
                    Annuler
                  </button>
                  <button type="submit" className="flex-1 px-4 py-2 bg-yellow-500 text-white rounded-lg hover:bg-yellow-600">
                    Créer la page
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}
      </div>
    </AdminLayout>
  );
}
